export function getRandomCard() {
  const randomIndex = Math.floor(Math.random() * TAROT_DECK.length);
  const isReversed = Math.random() > 0.5;
  return {
    ...TAROT_DECK[randomIndex],
    reversed: isReversed
  };
}
